  ('immigration-1aab856d-moex-00040', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '根據「役男出境處理辦法」，有關限制役男出境的情形，下列何者錯誤？', '["列入動員教召選員", "經通知徵兵體檢處理", "已列入梯次徵集對象", "歸化僑民尚未履行兵役義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00041', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '根據「入出國及移民法」第25條第1項第2款所稱外國人之不良素行，下列情形何者錯誤？', '["因犯罪受緩起訴處分", "在媒體公開批判我國政府政策者", "意圖鬥毆而聚眾經裁處拘留", "對具中華民國國籍家屬家庭暴力，法院判決確定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00042', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '根據「入出國及移民法」第18條，有關內政部移民署得禁止外國人入國之情形，下列何者錯誤？', '["攜帶違禁物", "曾經逾期停留、居留或非法工作", "曾參與臺灣政黨或政治活動", "在我國或國外有犯罪紀錄"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00043', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '繼承人甲在被繼承人乙之生前，獲得乙簽立文書以代為處理事務之授權，後乙死亡，甲繼續以乙 之名義製作私文書，甲於乙死後繼續製作私文書之行為是否違反刑法之相關規定？', '["甲構成偽造私文書罪，乙既死亡，原授權關係已消滅", "甲構成偽造私文書罪，但甲既然為繼承人，應不具備違法性", "甲不會構成偽造私文書罪，因甲為繼承人，當然繼承所有權利", "甲不會構成偽造私文書罪，因甲有獲得乙之授權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00044', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '30歲之甲與13歲之未成年人乙，在乙表示不同意之情境下違反其意願發生性交行為，依實務見 解，應如何評價甲之行為最為妥適？', '["論刑法第227條第1項之與未成年人性交罪", "論刑法第228條利用權勢性交罪", "論刑法第221條強制性交罪", "論刑法第222條加重強制性交罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00045', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '甲的孩子乙，目前就讀小學。一日乙放學後未直接回家，和同學在遊樂場玩樂；甲的鄰人丙認出 乙，忽然心生歹念，以匿名電話致電甲，謊稱自己綁架乙，若不將新臺幣五百萬元匯入指定帳戶， 將向黑市販售乙的器官。甲見乙未如同平常時間返家，又無從聯絡，心急如焚，只好依丙要求匯 款。依實務見解，下列敘述何者正確？', '["丙成立恐嚇取財罪", "丙成立詐欺取財罪", "丙成立擄人勒贖罪", "丙成立強盜罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00046', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '某鄉長選舉候選人甲，拜訪有投票權的鄉民乙時，贈以價值新臺幣五千元的知名品牌微電腦熱水 壺，並要求投票日當天惠賜選票，乙收下熱水壺後，口頭應允。下列敘述何者正確？', '["甲是贈乙熱水壺，而非金錢，所以不成立刑法第144條之投票行賄罪", "乙雖然口頭應允，內心沒有打算投票給甲，但仍成立刑法第143條之投票受賄罪", "乙收下熱水壺後，內心焦躁不安，乃將熱水壺退回候選人甲的競選總部，則不成立刑法第143 條之投票受賄罪", "投票行賄罪與投票受賄罪為實務所稱的對向犯，屬於必要共犯的一種，本質為共同正犯，故甲 乙成立刑法第143條之投票受賄罪的共同正犯"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00047', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '關於驅逐出境的敘述，下列何者正確？', '["外國人受有期徒刑之宣告者，得於赦免後，將之驅逐出境", "外國人受有期徒刑之宣告，並受緩刑之宣告者，得緩刑期滿後，將之驅逐出境", "外國人受罰金之宣告者，得於刑罰執行完畢後，將之驅逐出境", "外國人受無期徒刑之宣告者，得於假釋出獄後，將之驅逐出境"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00048', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '關於刑法第10條的刑法概念定義，依實務意見，下列敘述何者錯誤？', '["10年以上有期徒刑，包含10年，因為「以上」包含本數", "兇殘之徒砍斷被害人的拇指、食指及中指，因尚未毀敗他人一肢，所以非屬「重傷」", "私立大學具有核發畢業證書權限之人員，屬於「公務員」", "惡劣之徒非基於正當目的，以牙刷進入被害人的肛門，屬於「性交」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00049', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '在夜市，甲在竊取遊客乙的隨身財物時，恰巧被巡邏警察發現，並以現行犯逮捕。乙隨即向警方 提出告訴，經警方移送檢察官偵辦。下列敘述何者錯誤？', '["檢察官訊問後，若認為甲有逃亡之虞，但無聲請羈押必要，得直接命具保釋放", "乙事後選擇原諒甲，若向檢察官表示撤回告訴，檢察官應為不起訴處分，並釋放甲", "檢察官訊問後，向法院聲請羈押甲，若甲未選任辯護人，審判長應指定公設辯護人或律師為甲辯護", "檢察官經乙同意後為緩起訴處分，則乙接受該緩起訴處分書後，不得向檢察官聲請再議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
